  1→use std::io::{Cursor, Read, Stderr, Stdin, Stdout, Write};
  2→
  3→/// Abstracts stdin/stdout/stderr for dependency injection and testability.
  4→pub trait ConsoleIO<IN: Read, OUT: Write, ERR: Write> {
  5→    fn stdin(&mut self) -> &mut IN;
  6→    fn stdout(&mut self) -> &mut OUT;
  7→    fn stderr(&mut self) -> &mut ERR;
  8→}
  9→
 10→/// Real implementation that uses actual stdin/stdout/stderr.
 11→pub struct StdIO {
 12→    stdin: Stdin,
 13→    stdout: Stdout,
 14→    stderr: Stderr,
 15→}
 16→
 17→impl StdIO {
 18→    #[must_use]
 19→    pub fn new() -> Self {
 20→        Self {
 21→            stdin: std::io::stdin(),
 22→            stdout: std::io::stdout(),
 23→            stderr: std::io::stderr(),
 24→        }
 25→    }
 26→}
 27→
 28→impl Default for StdIO {
 29→    fn default() -> Self {
 30→        Self::new()
 31→    }
 32→}
 33→
 34→impl ConsoleIO<Stdin, Stdout, Stderr> for StdIO {
 35→    fn stdin(&mut self) -> &mut Stdin {
 36→        &mut self.stdin
 37→    }
 38→
 39→    fn stdout(&mut self) -> &mut Stdout {
 40→        &mut self.stdout
 41→    }
 42→
 43→    fn stderr(&mut self) -> &mut Stderr {
 44→        &mut self.stderr
 45→    }
 46→}
 47→
 48→/// Test implementation that captures output and provides canned stdin.
 49→pub struct BufferedIO {
 50→    stdin: Cursor<Vec<u8>>,
 51→    stdout: Vec<u8>,
 52→    stderr: Vec<u8>,
 53→}
 54→
 55→impl BufferedIO {
 56→    #[must_use]
 57→    pub fn new() -> Self {
 58→        Self::default()
 59→    }
 60→
 61→    /// Create a `BufferedIO` with pre-filled stdin data.
 62→    #[must_use]
 63→    pub fn with_stdin(data: &[u8]) -> Self {
 64→        Self {
 65→            stdin: Cursor::new(data.to_vec()),
 66→            ..Self::default()
 67→        }
 68→    }
 69→
 70→    /// Returns the captured stdout content as a string.
 71→    pub fn stdout_to_string(&self) -> String {
 72→        String::from_utf8_lossy(&self.stdout).into_owned()
 73→    }
 74→
 75→    /// Returns the captured stderr content as a string.
 76→    pub fn stderr_to_string(&self) -> String {
 77→        String::from_utf8_lossy(&self.stderr).into_owned()
 78→    }
 79→}
 80→
 81→impl Default for BufferedIO {
 82→    fn default() -> Self {
 83→        Self {
 84→            stdin: Cursor::new(Vec::new()),
 85→            stdout: Vec::new(),
 86→            stderr: Vec::new(),
 87→        }
 88→    }
 89→}
 90→
 91→impl ConsoleIO<Cursor<Vec<u8>>, Vec<u8>, Vec<u8>> for BufferedIO {
 92→    fn stdin(&mut self) -> &mut Cursor<Vec<u8>> {
 93→        &mut self.stdin
 94→    }
 95→
 96→    fn stdout(&mut self) -> &mut Vec<u8> {
 97→        &mut self.stdout
 98→    }
 99→
100→    fn stderr(&mut self) -> &mut Vec<u8> {
101→        &mut self.stderr
102→    }
103→}
104→
105→#[cfg(test)]
106→mod tests {
107→    use super::*;
108→
109→    #[test]
110→    fn buffered_io_captures_stdout() {
111→        let mut io = BufferedIO::new();
112→        writeln!(io.stdout(), "hello").unwrap();
113→        assert_eq!(io.stdout_to_string(), "hello\n");
114→    }
115→
116→    #[test]
117→    fn buffered_io_captures_stderr() {
118→        let mut io = BufferedIO::new();
119→        writeln!(io.stderr(), "error").unwrap();
120→        assert_eq!(io.stderr_to_string(), "error\n");
121→    }
122→
123→    #[test]
124→    fn buffered_io_starts_empty() {
125→        let io = BufferedIO::new();
126→        assert!(io.stdout_to_string().is_empty());
127→        assert!(io.stderr_to_string().is_empty());
128→    }
129→
130→    #[test]
131→    fn buffered_io_reads_stdin() {
132→        let mut io = BufferedIO::with_stdin(b"hello stdin");
133→        let mut buf = String::new();
134→        io.stdin().read_to_string(&mut buf).unwrap();
135→        assert_eq!(buf, "hello stdin");
136→    }
137→}
