660→    fn truncate_by_grapheme_cluster_count() {
661→        // Korean Hangul: each syllable is 1 grapheme cluster
662→        let s = "가나다라마바사"; // 7 graphemes
663→        assert_eq!(truncate(s, 3), "가나다...");
664→        assert_eq!(truncate(s, 7), "가나다라마바사"); // exact fit, no truncation
665→
666→        // Devanagari conjunct: क + ् + ष = 1 grapheme cluster
667→        let s = "क्षabc"; // 4 graphemes: क्ष, a, b, c
668→        assert_eq!(truncate(s, 2), "क्षa...");
669→
670→        // Emoji family: 👨‍👩‍👧‍👦 = 1 grapheme cluster
671→        let s = "👨\u{200D}👩\u{200D}👧\u{200D}👦abc"; // 4 graphemes
672→        assert_eq!(truncate(s, 2), "👨\u{200D}👩\u{200D}👧\u{200D}👦a...");
673→
674→        // ASCII: 1 char = 1 grapheme
675→        assert_eq!(truncate("hello world", 5), "hello...");
676→        assert_eq!(truncate("short", 10), "short"); // no truncation
677→    }
