 8→
 9→fn main() -> anyhow::Result<()> {
10→    // 1. Read env + classify worktree type + resolve project root
11→    let cwd = std::env::current_dir()?;
12→    let resolved = resolve_worktree(&cwd);
13→    let is_linked = resolved.is_linked();
14→    let project_root = resolved
15→        .primary_root()
16→        .map_or_else(|| cwd.clone(), Path::to_path_buf);
17→    let log_dir = std::env::var("MEMENTOR_LOG_DIR").ok().map(PathBuf::from);
18→    let context = MementorContext::with_cwd_and_log_dir(cwd, project_root, is_linked, log_dir)?;
19→
20→    // 2. Init file logging (no-op if log_dir is None)
21→    mementor_cli::logging::init_file_logging(&context);
22→
23→    // 3. Set panic hook (logs to file if available, always prints to stderr)
24→    std::panic::set_hook(Box::new(|info| {
25→        tracing::error!("{info}");
26→        eprintln!("{info}");
27→    }));
28→
29→    // 4. Build runtime
30→    let db = DatabaseDriver::file(context.db_path());
31→    let runtime = Runtime { context, db };
32→
33→    // 5. Run CLI
34→    let args: Vec<String> = std::env::args().collect();
35→    let args_refs: Vec<&str> = args.iter().map(String::as_str).collect();
36→    let mut io = StdIO::new();
37→
38→    let result = mementor_cli::try_run(&args_refs, &runtime, &mut io);
39→    if let Err(ref e) = result {
40→        tracing::error!(error = format!("{e:?}"), "command failed");
41→    }
42→    result
43→}
