 11→/// Create a [`Runtime`] with an in-memory database and a tempdir-based context.
 12→///
 13→/// The `name` must be unique per test to prevent cross-test DB collisions.
 14→/// The caller must hold the returned [`tempfile::TempDir`] to keep the
 15→/// temporary directory alive for the duration of the test.
 16→pub fn runtime_in_memory(name: &str) -> (tempfile::TempDir, Runtime) {
 17→    let tmp = tempfile::tempdir().unwrap();
 18→    // Create a bare .git directory so that the tempdir looks like a git repo.
 19→    std::fs::create_dir(tmp.path().join(".git")).unwrap();
 20→    let ctx = MementorContext::new(tmp.path().to_path_buf()).unwrap();
 21→    let db = DatabaseDriver::in_memory(name).unwrap();
 22→    let runtime = Runtime { context: ctx, db };
 23→    (tmp, runtime)
 24→}
 25→
 26→/// Create a [`Runtime`] where [`DatabaseDriver::is_ready`] returns `false`.
 27→///
 28→/// Uses a file-backed driver pointed at a nonexistent path, simulating a
 29→/// project where mementor has not been enabled.
 30→pub fn runtime_not_enabled() -> (tempfile::TempDir, Runtime) {
 31→    let tmp = tempfile::tempdir().unwrap();
 32→    let ctx = MementorContext::new(tmp.path().to_path_buf()).unwrap();
 33→    let db = DatabaseDriver::file(PathBuf::from("/nonexistent/mementor.db"));
 34→    let runtime = Runtime { context: ctx, db };
 35→    (tmp, runtime)
 36→}
