 34→    pub line_index: usize,
 35→    /// Entry type (e.g., `user`, `assistant`, `summary`, `file_history_snapshot`).
 36→    pub entry_type: String,
 37→    /// Text content of the entry.
 38→    pub content: String,
 39→    /// Tool summary string (pipe-separated, e.g., "Read(src/main.rs) | Edit(ci.yml)").
 40→    pub tool_summary: String,
 41→    /// Timestamp from the transcript entry.
