 56→/// Result of parsing a transcript file.
 57→#[derive(Debug)]
 58→pub struct ParseResult {
 59→    pub messages: Vec<ParsedMessage>,
 60→    pub pr_links: Vec<PrLinkEntry>,
 61→    pub raw_entries: Vec<RawEntry>,
 62→}
 63→
 64→impl ParsedMessage {
 65→    pub fn is_user(&self) -> bool {
 66→        matches!(self.role, MessageRole::User)
 67→    }
 68→
 69→    pub fn is_assistant(&self) -> bool {
 70→        matches!(self.role, MessageRole::Assistant { .. })
 71→    }
 72→}
 73→
 74→/// Entry types that are noise and should be skipped entirely.
 75→fn is_noise_type(entry_type: &str) -> bool {
 76→    matches!(
 77→        entry_type,
 78→        "progress" | "queue-operation" | "turn_duration" | "stop_hook_summary"
 79→    )
 80→}
 81→
 82→/// Outcome of processing a single transcript entry.
 83→enum EntryAction {
 84→    /// Push a PR link.
 85→    PrLink(PrLinkEntry),
 86→    /// Push a raw entry only (no parsed message).
 87→    RawOnly(RawEntry),
 88→    /// Push both a raw entry and a parsed message.
 89→    RawAndMessage(RawEntry, ParsedMessage),
 90→    /// Skip this line entirely.
 91→    Skip,
 92→}
 93→
 94→/// Classify and extract data from a single transcript entry.
 95→fn process_entry(line_idx: usize, entry: TranscriptEntry, line: &str) -> EntryAction {
 96→    let entry_type = entry.entry_type.as_deref().unwrap_or("");
 97→
 98→    if entry_type == "pr-link" {
 99→        if let Some(sid) = entry.session_id.as_ref()
100→            && let Some(pr_number) = entry.pr_number
101→            && let Some(pr_url) = entry.pr_url.as_ref()
102→            && let Some(pr_repo) = entry.pr_repository.as_ref()
103→            && let Some(ts) = entry.timestamp.as_ref()
104→        {
105→            return EntryAction::PrLink(PrLinkEntry {
106→                line_index: line_idx,
107→                session_id: sid.clone(),
108→                pr_number,
109→                pr_url: pr_url.clone(),
110→                pr_repository: pr_repo.clone(),
111→                timestamp: ts.clone(),
112→            });
113→        }
114→        return EntryAction::Skip;
115→    }
116→
117→    if is_noise_type(entry_type) {
118→        return EntryAction::Skip;
119→    }
120→
121→    // Resolve effective entry type for the entries table.
122→    // Real transcripts use `"type": "message"` with the actual role in `message.role`,
123→    // so we defer role-based resolution for "message" type to after parsing the message.
124→    let effective_type = match entry_type {
125→        "system" if entry.sub_type.as_deref() == Some("compact_boundary") => "compact_boundary",
126→        "file-history-snapshot" => "file_history_snapshot",
127→        "user" | "assistant" | "summary" | "message" => entry_type,
128→        _ => return EntryAction::Skip,
129→    };
130→
131→    let Some(message) = entry.message else {
132→        if effective_type == "compact_boundary" || effective_type == "file_history_snapshot" {
133→            return EntryAction::RawOnly(RawEntry {
134→                line_index: line_idx,
135→                entry_type: effective_type.to_string(),
136→                content: String::new(),
137→                tool_summary: String::new(),
138→                timestamp: entry.timestamp.clone(),
139→            });
140→        }
141→        return EntryAction::Skip;
142→    };
143→
144→    // For "message" type entries, resolve the effective type from the message role.
145→    let effective_type = if effective_type == "message" {
146→        message.role.as_str()
147→    } else {
148→        effective_type
149→    };
