 17→/// Parsed transcript messages with their line indices.
 18→#[derive(Debug)]
 19→pub struct ParsedMessage {
 20→    /// 0-based line index in the JSONL file.
 21→    pub line_index: usize,
 22→    /// Extracted text content (`tool_use`/`tool_result` blocks stripped).
 23→    pub text: String,
 24→    /// Role and role-specific data.
 25→    pub role: MessageRole,
 26→    /// Whether this message is a compaction summary (post-compaction context).
 27→    pub is_compaction_summary: bool,
 28→}
 29→
 30→/// A raw entry extracted from the transcript for storage in the `entries` table.
 31→#[derive(Debug, PartialEq)]
 32→pub struct RawEntry {
 33→    /// 0-based line index in the JSONL file.
 34→    pub line_index: usize,
 35→    /// Entry type (e.g., `user`, `assistant`, `summary`, `file_history_snapshot`).
 36→    pub entry_type: String,
 37→    /// Text content of the entry.
 38→    pub content: String,
 39→    /// Tool summary string (pipe-separated, e.g., "Read(src/main.rs) | Edit(ci.yml)").
 40→    pub tool_summary: String,
 41→    /// Timestamp from the transcript entry.
 42→    pub timestamp: Option<String>,
 43→}
 44→
 45→/// A PR link extracted from a transcript entry.
 46→#[derive(Debug, PartialEq)]
 47→pub struct PrLinkEntry {
 48→    pub line_index: usize,
 49→    pub session_id: String,
 50→    pub pr_number: u32,
 51→    pub pr_url: String,
 52→    pub pr_repository: String,
 53→    pub timestamp: String,
 54→}
 55→
 56→/// Result of parsing a transcript file.
 57→#[derive(Debug)]
 58→pub struct ParseResult {
 59→    pub messages: Vec<ParsedMessage>,
 60→    pub pr_links: Vec<PrLinkEntry>,
 61→    pub raw_entries: Vec<RawEntry>,
 62→}
 63→
 64→impl ParsedMessage {
 65→    pub fn is_user(&self) -> bool {
 66→        matches!(self.role, MessageRole::User)
 67→    }
 68→
 69→    pub fn is_assistant(&self) -> bool {
 70→        matches!(self.role, MessageRole::Assistant { .. })
 71→    }
 72→}
 73→
 74→/// Entry types that are noise and should be skipped entirely.
 75→fn is_noise_type(entry_type: &str) -> bool {
 76→    matches!(
 77→        entry_type,
 78→        "progress" | "queue-operation" | "turn_duration" | "stop_hook_summary"
 79→    )
 80→}
 81→
 82→/// Outcome of processing a single transcript entry.
 83→enum EntryAction {
 84→    /// Push a PR link.
 85→    PrLink(PrLinkEntry),
 86→    /// Push a raw entry only (no parsed message).
 87→    RawOnly(RawEntry),
 88→    /// Push both a raw entry and a parsed message.
 89→    RawAndMessage(RawEntry, ParsedMessage),
 90→    /// Skip this line entirely.
 91→    Skip,
 92→}
 93→
 94→/// Classify and extract data from a single transcript entry.
 95→fn process_entry(line_idx: usize, entry: TranscriptEntry, line: &str) -> EntryAction {
 96→    let entry_type = entry.entry_type.as_deref().unwrap_or("");
 97→
 98→    if entry_type == "pr-link" {
 99→        if let Some(sid) = entry.session_id.as_ref()
100→            && let Some(pr_number) = entry.pr_number
101→            && let Some(pr_url) = entry.pr_url.as_ref()
102→            && let Some(pr_repo) = entry.pr_repository.as_ref()
103→            && let Some(ts) = entry.timestamp.as_ref()
104→        {
105→            return EntryAction::PrLink(PrLinkEntry {
106→                line_index: line_idx,
107→                session_id: sid.clone(),
108→                pr_number,
109→                pr_url: pr_url.clone(),
110→                pr_repository: pr_repo.clone(),
111→                timestamp: ts.clone(),
112→            });
113→        }
114→        return EntryAction::Skip;
115→    }
116→
117→    if is_noise_type(entry_type) {
118→        return EntryAction::Skip;
119→    }
120→
121→    // Resolve effective entry type for the entries table.
122→    // Real transcripts use `"type": "message"` with the actual role in `message.role`,
123→    // so we defer role-based resolution for "message" type to after parsing the message.
124→    let effective_type = match entry_type {
125→        "system" if entry.sub_type.as_deref() == Some("compact_boundary") => "compact_boundary",
126→        "file-history-snapshot" => "file_history_snapshot",
127→        "user" | "assistant" | "summary" | "message" => entry_type,
128→        _ => return EntryAction::Skip,
129→    };
130→
131→    let Some(message) = entry.message else {
132→        if effective_type == "compact_boundary" || effective_type == "file_history_snapshot" {
133→            return EntryAction::RawOnly(RawEntry {
134→                line_index: line_idx,
135→                entry_type: effective_type.to_string(),
136→                content: String::new(),
137→                tool_summary: String::new(),
138→                timestamp: entry.timestamp.clone(),
139→            });
140→        }
141→        return EntryAction::Skip;
142→    };
143→
144→    // For "message" type entries, resolve the effective type from the message role.
145→    let effective_type = if effective_type == "message" {
146→        message.role.as_str()
147→    } else {
148→        effective_type
149→    };
150→
151→    if message.content.has_unknown_blocks() {
152→        debug!(line = line_idx, raw = %line, "message contains unknown content block type(s), ignoring those blocks");
153→    }
154→
155→    let role = match message.role.as_str() {
156→        "assistant" => MessageRole::Assistant {
157→            tool_summary: message.content.extract_tool_summary(),
158→        },
159→        "user" => MessageRole::User,
160→        _ => return EntryAction::Skip,
161→    };
162→
163→    let text = message.content.extract_text();
164→    let tool_summary_text = match &role {
165→        MessageRole::Assistant { tool_summary } if !tool_summary.is_empty() => {
166→            tool_summary.join(" | ")
167→        }
168→        _ => String::new(),
169→    };
170→
171→    let raw = RawEntry {
172→        line_index: line_idx,
173→        entry_type: effective_type.to_string(),
174→        content: text.clone(),
175→        tool_summary: tool_summary_text,
176→        timestamp: entry.timestamp.clone(),
177→    };
178→
179→    if text.trim().is_empty() && raw.tool_summary.is_empty() {
180→        return EntryAction::RawOnly(raw);
181→    }
182→
183→    let is_compaction_summary = matches!(&role, MessageRole::User)
184→        && text.starts_with(crate::config::COMPACTION_SUMMARY_PREFIX);
185→
186→    EntryAction::RawAndMessage(
187→        raw,
188→        ParsedMessage {
189→            line_index: line_idx,
190→            text,
191→            role,
192→            is_compaction_summary,
193→        },
194→    )
195→}
196→
197→/// Read transcript JSONL file starting from `start_line` (0-based).
198→/// Returns parsed messages with user/assistant text content, plus any PR link
199→/// entries found in the transcript, plus raw entries for the `entries` table.
200→pub fn parse_transcript(path: &Path, start_line: usize) -> anyhow::Result<ParseResult> {
201→    let file = File::open(path)
202→        .with_context(|| format!("Failed to open transcript: {}", path.display()))?;
203→    let reader = BufReader::new(file);
204→    let mut messages = Vec::new();
205→    let mut pr_links = Vec::new();
206→    let mut raw_entries = Vec::new();
207→
208→    for (line_idx, line_result) in reader.lines().enumerate() {
209→        if line_idx < start_line {
210→            continue;
211→        }
212→
213→        let line = match line_result {
214→            Ok(l) => l,
215→            Err(e) => {
216→                warn!(line = line_idx, error = %e, "Failed to read line, skipping");
217→                continue;
218→            }
219→        };
220→
221→        if line.trim().is_empty() {
222→            continue;
223→        }
224→
225→        let entry: TranscriptEntry = match serde_json::from_str(&line) {
226→            Ok(e) => e,
227→            Err(e) => {
228→                warn!(line = line_idx, error = %e, "Failed to parse JSON line, skipping");
229→                continue;
230→            }
231→        };
232→
233→        match process_entry(line_idx, entry, &line) {
234→            EntryAction::PrLink(pr) => pr_links.push(pr),
235→            EntryAction::RawOnly(raw) => raw_entries.push(raw),
236→            EntryAction::RawAndMessage(raw, msg) => {
237→                raw_entries.push(raw);
238→                messages.push(msg);
239→            }
240→            EntryAction::Skip => {}
241→        }
242→    }
243→
244→    Ok(ParseResult {
245→        messages,
246→        pr_links,
247→        raw_entries,
248→    })
249→}
