 10→#[allow(unsafe_code)]
 11→unsafe extern "C" {
 12→    fn sqlite3_vector_init(
 13→        db: *mut rusqlite::ffi::sqlite3,
 14→        pz_err_msg: *mut *mut std::ffi::c_char,
 15→        p_api: *const rusqlite::ffi::sqlite3_api_routines,
 16→    ) -> std::ffi::c_int;
 17→}
 18→
 19→/// Open a file-backed `SQLite` connection with sqlite-vector loaded and schema applied.
 20→pub fn open_db(path: &Path) -> anyhow::Result<Connection> {
 21→    if let Some(parent) = path.parent() {
 22→        std::fs::create_dir_all(parent)
 23→            .with_context(|| format!("Failed to create directory: {}", parent.display()))?;
 24→    }
 25→
 26→    let mut conn = Connection::open(path)
 27→        .with_context(|| format!("Failed to open database: {}", path.display()))?;
 28→    init_connection(&mut conn)?;
 29→    Ok(conn)
 30→}
 31→
 32→/// Open an in-memory `SQLite` connection with sqlite-vector loaded and schema applied.
 33→///
 34→/// Uses the `SQLite` URI format with shared-cache mode so multiple connections
 35→/// can share the same named in-memory database within the same process.
 36→/// The in-memory database persists as long as at least one connection to it remains open.
 37→pub fn open_db_in_memory(name: &str) -> anyhow::Result<Connection> {
 38→    let uri = format!("file:{name}?mode=memory&cache=shared");
 39→    let flags = OpenFlags::SQLITE_OPEN_READ_WRITE
 40→        | OpenFlags::SQLITE_OPEN_CREATE
 41→        | OpenFlags::SQLITE_OPEN_URI
 42→        | OpenFlags::SQLITE_OPEN_SHARED_CACHE
 43→        | OpenFlags::SQLITE_OPEN_NO_MUTEX;
 44→
 45→    let mut conn = Connection::open_with_flags(uri, flags)
 46→        .with_context(|| format!("Failed to open in-memory database: {name}"))?;
 47→    init_connection(&mut conn)?;
 48→    Ok(conn)
 49→}
 50→
 51→/// Load sqlite-vector extension, apply schema migrations, register vector table,
 52→/// and configure WAL mode for safe concurrent access from multiple worktrees.
 53→fn init_connection(conn: &mut Connection) -> anyhow::Result<()> {
 54→    conn.pragma_update(None, "journal_mode", "WAL")
 55→        .context("Failed to enable WAL mode")?;
 56→    conn.pragma_update(None, "busy_timeout", 5000)
 57→        .context("Failed to set busy_timeout")?;
 58→    conn.pragma_update(None, "foreign_keys", true)
 59→        .context("Failed to enable foreign keys")?;
 60→    register_vector_extension(conn)?;
 61→    apply_migrations(conn)?;
 62→    register_vector_table(conn)?;
 63→    Ok(())
 64→}
 65→
 66→/// Register the sqlite-vector extension into the connection.
 67→#[allow(unsafe_code)]
 68→fn register_vector_extension(conn: &Connection) -> anyhow::Result<()> {
 69→    let rc = unsafe {
 70→        let db_ptr = conn.handle();
 71→        sqlite3_vector_init(db_ptr, std::ptr::null_mut(), std::ptr::null())
 72→    };
 73→
 74→    if rc != rusqlite::ffi::SQLITE_OK {
 75→        anyhow::bail!("sqlite3_vector_init failed with code {rc}");
 76→    }
 77→
 78→    Ok(())
 79→}
 80→
 81→/// Register the `chunks.embedding` column with sqlite-vector for search.
 82→/// Must be called after migrations have created the `chunks` table.
 83→fn register_vector_table(conn: &Connection) -> anyhow::Result<()> {
 84→    let options = format!("type=f32, dimension={EMBEDDING_DIMENSION}, distance=cosine");
 85→    conn.query_row(
 86→        "SELECT vector_init('chunks', 'embedding', ?1)",
 87→        params![options],
 88→        |_row| Ok(()),
 89→    )
 90→    .context("Failed to call vector_init for chunks table")?;
 91→    Ok(())
 92→}
