 56→/// Append `.mementor/` to `.gitignore` if not already present.
 57→fn update_gitignore(ctx: &MementorContext) -> anyhow::Result<()> {
 58→    let gitignore_path = ctx.gitignore_path();
 59→    let entry = ".mementor/";
 60→
 61→    if gitignore_path.exists() {
 62→        let existing = std::fs::read_to_string(&gitignore_path)?;
 63→        if existing.lines().any(|line| line.trim() == entry) {
 64→            return Ok(());
 65→        }
 66→        // Append with newline separator
 67→        let separator = if existing.ends_with('\n') { "" } else { "\n" };
 68→        std::fs::write(&gitignore_path, format!("{existing}{separator}{entry}\n"))?;
 69→    } else {
 70→        std::fs::write(&gitignore_path, format!("{entry}\n"))?;
 71→    }
 72→
 73→    Ok(())
 74→}
