 76→/// Add mementor hooks to `.claude/settings.json`.
 77→fn configure_hooks(ctx: &MementorContext) -> anyhow::Result<()> {
 78→    let settings_path = ctx.claude_settings_path();
 79→
 80→    // Ensure .claude/ directory exists
 81→    if let Some(parent) = settings_path.parent() {
 82→        std::fs::create_dir_all(parent)?;
 83→    }
 84→
 85→    let (mut settings, has_trailing_newline): (serde_json::Value, bool) = if settings_path.exists()
 86→    {
 87→        let raw = std::fs::read_to_string(&settings_path)?;
 88→        let trailing = raw.ends_with('\n');
 89→        (serde_json::from_str(&raw)?, trailing)
 90→    } else {
 91→        (serde_json::json!({}), true)
 92→    };
 93→
 94→    // Build hook config — only Stop and PreCompact
 95→    let stop_hook = serde_json::json!({
 96→        "hooks": [{
 97→            "type": "command",
 98→            "command": "mementor hook stop"
 99→        }]
100→    });
101→
102→    let pre_compact_hook = serde_json::json!({
103→        "hooks": [{
104→            "type": "command",
105→            "command": "mementor hook pre-compact"
106→        }]
107→    });
108→
109→    // Merge hooks into settings
110→    let hooks = settings
111→        .as_object_mut()
112→        .ok_or_else(|| anyhow::anyhow!("settings.json root is not an object"))?
113→        .entry("hooks")
114→        .or_insert_with(|| serde_json::json!({}));
115→
116→    let hooks_obj = hooks
117→        .as_object_mut()
118→        .ok_or_else(|| anyhow::anyhow!("hooks field is not an object"))?;
119→
120→    // Upsert mementor hooks (replace existing mementor entries, preserve others)
121→    upsert_hook_entry(hooks_obj, "Stop", stop_hook);
122→    upsert_hook_entry(hooks_obj, "PreCompact", pre_compact_hook);
123→
124→    // Write settings back, preserving original EOF newline behavior
125→    let mut formatted = serde_json::to_string_pretty(&settings)?;
126→    if has_trailing_newline {
127→        formatted.push('\n');
128→    }
129→    std::fs::write(&settings_path, formatted)?;
130→
131→    Ok(())
132→}
