  9→/// Run the `mementor ingest` command.
 10→pub fn run_ingest_cmd<IN, OUT, ERR>(
 11→    transcript: &str,
 12→    session_id: &str,
 13→    runtime: &Runtime,
 14→    io: &mut dyn ConsoleIO<IN, OUT, ERR>,
 15→) -> anyhow::Result<()>
 16→where
 17→    IN: Read,
 18→    OUT: Write,
 19→    ERR: Write,
 20→{
 21→    if !runtime.db.is_ready() {
 22→        anyhow::bail!("mementor is not enabled. Run `mementor enable` first.");
 23→    }
 24→
 25→    let mut conn = runtime.db.open()?;
 26→    let mut embedder = Embedder::new(runtime.context.model_cache_dir())?;
 27→
 28→    let transcript_path = Path::new(transcript);
 29→    if !transcript_path.exists() {
 30→        anyhow::bail!("Transcript file not found: {transcript}");
 31→    }
 32→
 33→    let cwd = std::env::current_dir()?.to_string_lossy().to_string();
 34→    let project_root = runtime.context.project_root().to_string_lossy().to_string();
 35→    run_ingest(
 36→        &mut conn,
 37→        &mut embedder,
 38→        session_id,
 39→        transcript_path,
 40→        &cwd,
 41→        &project_root,
 42→    )?;
 43→
 44→    writeln!(io.stdout(), "Ingestion complete for session {session_id}.")?;
 45→    Ok(())
 46→}
