 10→/// Hugging Face repository for the GTE multilingual base model.
 11→const HF_REPO: &str = "onnx-community/gte-multilingual-base";
 12→
 13→/// Mapping of (remote path in HF repo, local file name) for model files.
 14→const MODEL_FILES: &[(&str, &str)] = &[
 15→    ("onnx/model_int8.onnx", MODEL_ONNX_FILE),
 16→    ("tokenizer.json", MODEL_TOKENIZER_FILE),
 17→    ("config.json", MODEL_CONFIG_FILE),
