 22→/// Run the `mementor model download` command.
 23→pub fn run_model_download<IN, OUT, ERR>(
 24→    force: bool,
 25→    runtime: &Runtime,
 26→    io: &mut dyn ConsoleIO<IN, OUT, ERR>,
 27→) -> anyhow::Result<()>
 28→where
 29→    IN: Read,
 30→    OUT: Write,
 31→    ERR: Write,
 32→{
 33→    let model_dir = runtime.context.model_cache_dir().join(MODEL_SUBDIR);
 34→
 35→    if force && model_dir.exists() {
 36→        writeln!(io.stderr(), "Removing existing model files...")?;
 37→        std::fs::remove_dir_all(&model_dir)?;
 38→    }
 39→
 40→    // Check if all files already exist
 41→    if !force
 42→        && MODEL_FILES
 43→            .iter()
 44→            .all(|(_, local)| model_dir.join(local).exists())
 45→    {
 46→        writeln!(
 47→            io.stdout(),
 48→            "Model already downloaded at {}",
 49→            model_dir.display()
 50→        )?;
 51→        return Ok(());
 52→    }
 53→
 54→    std::fs::create_dir_all(&model_dir)?;
 55→
 56→    writeln!(io.stderr(), "Downloading GTE multilingual base int8...")?;
 57→    let api = hf_hub::api::sync::Api::new()?;
 58→    let repo = api.model(HF_REPO.to_string());
 59→
 60→    for (remote_path, local_name) in MODEL_FILES {
 61→        let dest = model_dir.join(local_name);
 62→        if dest.exists() {
 63→            writeln!(io.stderr(), "  {local_name} (cached)")?;
 64→            continue;
 65→        }
 66→        writeln!(io.stderr(), "  {local_name}...")?;
 67→        let cached = repo.get(remote_path)?;
 68→        std::fs::copy(&cached, &dest)?;
 69→    }
 70→
 71→    writeln!(io.stdout(), "Model downloaded to {}", model_dir.display())?;
 72→    Ok(())
 73→}
