 12→/// Handle the Stop hook: parse stdin, run incremental ingest.
 13→pub fn handle_stop<IN, OUT, ERR>(
 14→    input: &StopHookInput,
 15→    runtime: &Runtime,
 16→    io: &mut dyn ConsoleIO<IN, OUT, ERR>,
 17→) -> anyhow::Result<()>
 18→where
 19→    IN: Read,
 20→    OUT: Write,
 21→    ERR: Write,
 22→{
 23→    debug!(
 24→        hook = "Stop",
 25→        session_id = %input.session_id,
 26→        transcript_path = %input.transcript_path,
 27→        cwd = %input.cwd,
 28→        "Hook received"
 29→    );
 30→
 31→    if !runtime.db.is_ready() {
 32→        writeln!(
 33→            io.stderr(),
 34→            "mementor is not enabled for this project. Run `mementor enable` first."
 35→        )?;
 36→        return Ok(());
 37→    }
 38→
 39→    let mut conn = runtime.db.open()?;
 40→    let mut embedder = Embedder::new(runtime.context.model_cache_dir())?;
 41→
 42→    let project_root = runtime.context.project_root().to_string_lossy();
 43→    run_ingest(
 44→        &mut conn,
 45→        &mut embedder,
 46→        &input.session_id,
 47→        Path::new(&input.transcript_path),
 48→        &input.cwd,
 49→        &project_root,
 50→    )?;
 51→
 52→    Ok(())
 53→}
