 10→/// Role-specific data for a parsed message.
 11→#[derive(Debug, PartialEq)]
 12→pub enum MessageRole {
 13→    User,
 14→    Assistant { tool_summary: Vec<String> },
 15→}
 16→
 17→/// Parsed transcript messages with their line indices.
 18→#[derive(Debug)]
 19→pub struct ParsedMessage {
 20→    /// 0-based line index in the JSONL file.
 21→    pub line_index: usize,
 22→    /// Extracted text content (`tool_use`/`tool_result` blocks stripped).
 23→    pub text: String,
 24→    /// Role and role-specific data.
 25→    pub role: MessageRole,
 26→    /// Whether this message is a compaction summary (post-compaction context).
 27→    pub is_compaction_summary: bool,
