208→/// A PR link associated with a session.
209→#[derive(Debug, PartialEq)]
210→pub struct PrLink {
211→    pub session_id: String,
212→    pub pr_number: u32,
213→    pub pr_url: String,
214→    pub pr_repository: String,
215→    pub timestamp: String,
216→}
217→
218→/// Insert a PR link for a session. Uses `INSERT OR IGNORE` for idempotency.
219→pub fn insert_pr_link(
220→    conn: &Connection,
221→    session_id: &str,
222→    pr_number: u32,
223→    pr_url: &str,
224→    pr_repository: &str,
225→    timestamp: &str,
226→) -> anyhow::Result<()> {
227→    conn.execute(
228→        "INSERT OR IGNORE INTO pr_links (session_id, pr_number, pr_url, pr_repository, timestamp)
229→         VALUES (?1, ?2, ?3, ?4, ?5)",
230→        params![session_id, pr_number, pr_url, pr_repository, timestamp],
231→    )
232→    .context("Failed to insert PR link")?;
233→    Ok(())
234→}
235→
236→/// Get all PR links for a session, ordered by `pr_number` ascending.
237→pub fn get_pr_links_for_session(
238→    conn: &Connection,
239→    session_id: &str,
240→) -> anyhow::Result<Vec<PrLink>> {
241→    let mut stmt = conn
242→        .prepare(
243→            "SELECT session_id, pr_number, pr_url, pr_repository, timestamp
244→             FROM pr_links WHERE session_id = ?1
245→             ORDER BY pr_number ASC",
246→        )
247→        .context("Failed to prepare get_pr_links_for_session query")?;
248→
249→    let results = stmt
250→        .query_map(params![session_id], |row| {
251→            Ok(PrLink {
252→                session_id: row.get(0)?,
253→                pr_number: row.get(1)?,
254→                pr_url: row.get(2)?,
255→                pr_repository: row.get(3)?,
256→                timestamp: row.get(4)?,
257→            })
258→        })?
259→        .collect::<Result<Vec<_>, _>>()
260→        .context("Failed to query PR links")?;
261→
262→    Ok(results)
263→}
